
"use client";

import { useState, useEffect, useTransition } from 'react';
import Link from 'next/link';
import { SiteHeader } from "@/components/SiteHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { PlusCircle, Trash2, Edit, Loader2 } from 'lucide-react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { getVendors, addVendor, type Vendor } from '@/ai/flows/vendor-flow';

export default function AdminPage() {
    const { toast } = useToast();
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [newVendorName, setNewVendorName] = useState('');
    const [newVendorDescription, setNewVendorDescription] = useState('');
    const [isLoading, setIsLoading] = useState(true);
    const [isPending, startTransition] = useTransition();

    const fetchVendors = async () => {
      setIsLoading(true);
      try {
        const fetchedVendors = await getVendors();
        setVendors(fetchedVendors.filter(v => v.isActive));
      } catch (error) {
        console.error("讀取店家失敗:", error);
        toast({
          variant: "destructive",
          title: "讀取店家失敗",
          description: error instanceof Error ? error.message : "無法從 Google Sheet 讀取店家列表。",
        });
      } finally {
        setIsLoading(false);
      }
    };

    useEffect(() => {
      fetchVendors();
    }, []);


    const handleAddVendor = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newVendorName.trim()) {
            toast({
                variant: "destructive",
                title: "請輸入店家名稱",
            });
            return;
        }

        startTransition(async () => {
            try {
                await addVendor({ name: newVendorName, description: newVendorDescription });
                toast({
                    title: "店家已成功新增",
                    description: `${newVendorName} 已新增到您的店家列表。`,
                });
                setNewVendorName('');
                setNewVendorDescription('');
                await fetchVendors(); 
            } catch (error) {
                console.error("新增店家失敗:", error);
                toast({
                    variant: "destructive",
                    title: "新增店家失敗",
                    description: error instanceof Error ? error.message : "無法將店家資料寫入 Google Sheet。",
                });
            }
        });
    };

    const handleDeleteVendor = (vendorId: string, vendorName: string) => {
        // TODO: Implement vendor deletion flow
        console.log("正在刪除店家 (尚未實作):", vendorId);
        toast({
            title: "刪除功能尚未實作",
            description: `刪除 ${vendorName} 的功能將在後續步驟中加入。`,
        });
    };

  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <h1 className="font-headline text-3xl font-bold mb-6">管理介面</h1>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Add New Vendor */}
            <section>
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <PlusCircle className="h-6 w-6" />
                            <span>新增店家</span>
                        </CardTitle>
                        <CardDescription>在這裡建立新的便當店家。</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleAddVendor} className="space-y-4">
                            <Input
                                placeholder="店家名稱"
                                value={newVendorName}
                                onChange={(e) => setNewVendorName(e.target.value)}
                                disabled={isPending}
                            />
                            <Input
                                placeholder="店家描述 (選填)"
                                value={newVendorDescription}
                                onChange={(e) => setNewVendorDescription(e.target.value)}
                                disabled={isPending}
                            />
                            <Button type="submit" className="w-full" disabled={isPending}>
                                {isPending ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" /> 新增中...</> : '新增店家'}
                            </Button>
                        </form>
                    </CardContent>
                </Card>
            </section>

            {/* Vendor List */}
            <section>
                <Card>
                    <CardHeader>
                        <CardTitle>店家列表</CardTitle>
                        <CardDescription>管理現有的店家及菜單。</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        {isLoading ? (
                            <div className="flex justify-center items-center py-4">
                                <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                                <p className="ml-2 text-muted-foreground">讀取中...</p>
                            </div>
                        ) : vendors.length > 0 ? (
                            vendors.map(vendor => (
                                <Card key={vendor.id} className="p-4 flex justify-between items-center">
                                    <div>
                                        <p className="font-semibold">{vendor.name}</p>
                                        <p className="text-sm text-muted-foreground">{vendor.description}</p>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Link href={`/admin/menu/${vendor.id}?name=${encodeURIComponent(vendor.name)}`}>
                                          <Button variant="outline" size="sm" className="flex items-center gap-1" disabled={isPending}>
                                            <Edit className="h-3 w-3" />
                                            編輯菜單
                                          </Button>
                                        </Link>
                                        <AlertDialog>
                                            <AlertDialogTrigger asChild>
                                                <Button variant="ghost" size="icon" aria-label={`刪除店家 ${vendor.name}`} disabled={isPending}>
                                                    <Trash2 className="h-4 w-4 text-destructive" />
                                                </Button>
                                            </AlertDialogTrigger>
                                            <AlertDialogContent>
                                                <AlertDialogHeader>
                                                    <AlertDialogTitle>確定要刪除店家嗎？</AlertDialogTitle>
                                                    <AlertDialogDescription>
                                                        此動作將會把店家設定為「非啟用」狀態，但不會真的從資料庫刪除。
                                                    </AlertDialogDescription>
                                                </AlertDialogHeader>
                                                <AlertDialogFooter>
                                                    <AlertDialogCancel>取消</AlertDialogCancel>
                                                    <AlertDialogAction onClick={() => handleDeleteVendor(vendor.id, vendor.name)} disabled={isPending}>確定</AlertDialogAction>
                                                </AlertDialogFooter>
                                            </AlertDialogContent>
                                        </AlertDialog>
                                    </div>
                                </Card>
                            ))
                        ) : (
                          <p className="text-sm text-center text-muted-foreground py-4">您的美食地圖還是空的，快來插上第一支旗幟吧！</p>
                        )}
                    </CardContent>
                </Card>
            </section>
        </div>
      </main>
    </div>
  );
}
